refsection.programlisting:
left = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
left = imresize(rgb2gray(left), [80 120]);
shift = 6;
right = left * 0;
right(:, 1:$-shift) = left(:, shift+1:$);
disparity = imstereobm(left, right, 10, 5);
subplot(1, 3, 1);
imshow(left);
subplot(1, 3, 2);
imshow(right);
subplot(1, 3, 3);
imshow(immat2gray(disparity), hot(64));
